 console.log('[Permission] Micro now available — refreshing');
 updatePermStatus('granted');
 await refreshDeviceList();
 showToast('Micro autorisé ✓');
 } catch {
 // Toujours bloqué — continuer le polling
 }
 }, 3000); // Vérifie toutes les 3 secondes
}

// Appeler startPermissionPolling() quand updatePermStatus reçoit 'denied'
// Arrêter le polling quand la permission est 'granted'
```

### 4. Améliorer le message UX quand la permission est denied

Dans `updatePermStatus('denied')`, remplacer le message statique par un message plus informatif avec action :
```javascript
} else if (state === 'denied') {
 permStatus.innerHTML = 'Micro bloqué — <strong>Étape 1:</strong> Cliquez sur le cadenas 🔒 → Microphone → Autoriser. <strong>Étape 2:</strong> Cliquez "Autoriser le micro" ci-dessous.';
